module base(data, sel);
	parameter MSB = 0;
	parameter LSB = 0;
	localparam big_endian = MSB < LSB;

	input [MSB:LSB] data;
	input [2:0] sel;

	wire [1:0] o = data[sel-:2];
	wire signed [3:0] sel_signed = sel;
	wire [1:0] o2 = (big_endian ?
							{data[sel_signed - 1], data[sel]}
							: {data[sel], data[sel_signed - 1]});

	always @* begin
		if (sel[0] === 1'bx ||
				sel[1] === 1'bx ||
				sel[2] === 1'bx) begin
			assert(o === 2'bxx);
		end else begin
			assert(o === (big_endian ?
							{data[sel_signed - 1], data[sel]}
							: {data[sel], data[sel_signed - 1]}));
		end
	end
endmodule

module test_partsel_down01(data, sel);
	input [4:-2] data;
	input [2:0] sel;
	base #(.MSB(4), .LSB(-2)) t(.*);
endmodule

